#include <iostream>
#include <iomanip>

class Time {
private:
    int hours;
    int minutes;
    int seconds;

    void normalize() {
        minutes += seconds / 60;
        seconds %= 60;
        if (seconds < 0) {
            seconds += 60;
            minutes--;
        }

        hours += minutes / 60;
        minutes %= 60;
        if (minutes < 0) {
            minutes += 60;
            hours--;
        }

        hours %= 24;
        if (hours < 0) {
            hours += 24;
        }
    }

public:
    Time(int h, int m, int s) : hours(h), minutes(m), seconds(s) {
        normalize();
    }

    Time() : Time(0, 0, 0) {}

    Time(int h) : Time(h, 0, 0) {}

    void display() const {
        std::cout << std::setfill('0') << std::setw(2) << hours << ":"
                  << std::setfill('0') << std::setw(2) << minutes << ":"
                  << std::setfill('0') << std::setw(2) << seconds << std::endl;
    }
};

int main() {
    Time t1;
    Time t2(5);
    Time t3(15, 30, 45);
    Time t4(23, 59, 59);
    Time t5(0, 0, 0);
    Time t6(25, 65, 70);
    Time t7(10, -5, 0);
    Time t8(0, 0, -1);
    Time t9(-2, 10, 20);
    Time t10(24, 0, 0);
    Time t11(0, 60, 0);
    Time t12(0, 0, 60);
    Time t13(48, 120, 120);

    t1.display();
    t2.display();
    t3.display();
    t4.display();
    t5.display();
    t6.display();
    t7.display();
    t8.display();
    t9.display();
    t10.display();
    t11.display();
    t12.display();
    t13.display();

    return 0;
}
